23	function authRole(role) {
24	  return (req, res, next) => {
25	    const token = req.headers.authorization
26	    if (!token) {
27	      return res.status(403).send("A token is required for authentication");
28	    }
29	    return jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
30	      if (err) {
31	        return res.status(403).send("Invalid Token");
32	      } else {
33	        for (var i = 0; i < role.length; i++) {
34	          if (decoded.role === role[i] || decoded.role === "admin") {
35	            return next();
